@namespace sv_7ae0d7b3e52d4594b7e6607032016ee8.Components.Chat

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-option" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)" title="@emoji">
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "😢"];
}

.emoji-picker {
    display: flex;
    gap: 2px;
    background: var(--bs-body-bg, #fff);
    border: 1px solid var(--bs-border-color, #dee2e6);
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    padding: 4px 6px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.emoji-option:hover {
    background: var(--bs-tertiary-bg, #f0f0f0);
}

