arguments.file_text:
@namespace sv_7ae0d7b3e52d4594b7e6607032016ee8.Components.Chat
@using sv_7ae0d7b3e52d4594b7e6607032016ee8.Services

<div class="message-item" @onmouseenter="() => _hovered = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp" title="@Message.SentAt.ToString("f")">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reaction-bar">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync((Message.Id, reaction.Emoji))"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)">
            @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_hovered)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message.Id)" title="Reply in thread">
                💬
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😀
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker-container">
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public Message Message { get; set; } = default!;

    [Parameter]
    public int ThreadReplyCount { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    /// <summary>Passes (messageId, emoji).</summary>
    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private bool _hovered;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _hovered = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReact.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 600;
    font-size: 0.95rem;
    color: #2c2f33;
}

.timestamp {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    color: #2e3338;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reaction-bar {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #e3e5e8;
    border: 1px solid #d3d5d8;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    line-height: 1.4;
}

.reaction-badge:hover {
    background: #c8ccd0;
}

.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    padding: 2px 0;
    margin-top: 4px;
    cursor: pointer;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
}

.action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.action-btn:hover {
    background: #e3e5e8;
}

.emoji-picker-container {
    position: absolute;
    top: -12px;
    right: 80px;
    z-index: 10;
}

