@namespace sv_7ae0d7b3e52d4594b7e6607032016ee8.Components.Chat
@using sv_7ae0d7b3e52d4594b7e6607032016ee8.Services
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        <h5># @Channel.Name</h5>
        <span class="area-desc">@Channel.Description</span>
    </div>

    <div class="message-list" @ref="_messageListRef" @onscroll="HandleScroll">
        @if (_loadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadReplyCount="GetReplyCount(msg.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <div class="message-input">
        <textarea @bind="NewMessageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Message #@Channel.Name" rows="2"></textarea>
        <button class="btn btn-primary send-btn" disabled="@string.IsNullOrWhiteSpace(NewMessageText)"
                @onclick="HandleSend">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Channel Channel { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<Message> Messages { get; set; } = [];

    [Parameter]
    public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback<int> OnOpenThread { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendMessage { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadOlderMessages { get; set; }

    private string NewMessageText { get; set; } = "";
    private ElementReference _messageListRef;
    private bool _loadingMore;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottomAsync();
        }
    }

    private async Task ScrollToBottomAsync()
    {
        try
        {
            await JS.InvokeVoidAsync("eval",
                "document.querySelector('[data-scroll-bottom]')?.scrollTo(0, document.querySelector('[data-scroll-bottom]').scrollHeight)");
        }
        catch
        {
            // Ignore JS interop errors during prerendering
        }
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers loading older messages
        try
        {
            var scrollTop = await JS.InvokeAsync<double>("eval",
                "document.querySelector('[data-scroll-bottom]')?.scrollTop ?? 1");
            if (scrollTop < 50 && !_loadingMore)
            {
                _loadingMore = true;
                await OnLoadOlderMessages.InvokeAsync();
                _loadingMore = false;
            }
        }
        catch
        {
            // Ignore JS interop errors
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        if (string.IsNullOrWhiteSpace(NewMessageText)) return;
        var text = NewMessageText.Trim();
        NewMessageText = "";
        await OnSendMessage.InvokeAsync(text);
        await ScrollToBottomAsync();
    }

    private int GetReplyCount(int messageId)
    {
        return ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;
    }
}

