@namespace sv_7ae0d7b3e52d4594b7e6607032016ee8.Components.Chat
@using sv_7ae0d7b3e52d4594b7e6607032016ee8.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="close-btn" @onclick="OnClose" title="Close thread">&times;</button>
    </div>

    <div class="thread-root-quote">
        <div class="quote-author">@RootMessage.Author</div>
        <div class="quote-content">@RootMessage.Content</div>
    </div>

    <div class="thread-replies">
        @if (Replies.Count == 0)
        {
            <div class="no-replies">No replies yet</div>
        }
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="reply-author">@reply.Author</span>
                    <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="reply-content">@reply.Content</div>
            </div>
        }
    </div>

    <div class="thread-input">
        <textarea @bind="ReplyText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown"
                  placeholder="Reply…" rows="2"></textarea>
        <button class="btn btn-primary reply-btn" disabled="@string.IsNullOrWhiteSpace(ReplyText)"
                @onclick="HandleReply">
            Reply
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Message RootMessage { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<Message> Replies { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback OnClose { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnSendReply { get; set; }

    private string ReplyText { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleReply();
        }
    }

    private async Task HandleReply()
    {
        if (string.IsNullOrWhiteSpace(ReplyText)) return;
        var text = ReplyText.Trim();
        ReplyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #dee2e6;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #dee2e6;
    flex-shrink: 0;
}

.thread-header h6 {
    margin: 0;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.5rem;
    line-height: 1;
    color: #72767d;
    cursor: pointer;
    padding: 0 4px;
}

.close-btn:hover {
    color: #2c2f33;
}

.thread-root-quote {
    padding: 12px 16px;
    background: #f2f3f5;
    border-left: 3px solid #5865f2;
    margin: 8px 12px;
    border-radius: 0 4px 4px 0;
}

.quote-author {
    font-weight: 600;
    font-size: 0.85rem;
    color: #2c2f33;
}

.quote-content {
    font-size: 0.85rem;
    color: #4f5660;
    margin-top: 2px;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.no-replies {
    text-align: center;
    color: #72767d;
    padding: 24px;
    font-size: 0.85rem;
}

.thread-reply {
    padding: 8px 16px;
}

.thread-reply:hover {
    background: #f8f9fa;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    font-size: 0.85rem;
    color: #2c2f33;
}

.reply-time {
    font-size: 0.7rem;
    color: #72767d;
}

.reply-content {
    font-size: 0.85rem;
    color: #2e3338;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-input {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 12px;
    border-top: 1px solid #dee2e6;
    flex-shrink: 0;
}

.thread-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.85rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.thread-input textarea:focus {
    border-color: #5865f2;
    box-shadow: 0 0 0 2px rgba(88, 101, 242, 0.15);
}

.reply-btn {
    padding: 8px 16px;
    border-radius: 8px;
    font-size: 0.85rem;
    font-weight: 500;
}

