@page "/chat"
@using sv_7ae0d7b3e52d4594b7e6607032016ee8.Components.Chat
@using sv_7ae0d7b3e52d4594b7e6607032016ee8.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        ActiveChannelId="_activeChannelId"
                        OnChannelSelected="HandleChannelSelected" />
    </div>

    <div class="chat-main @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <MessageArea Channel="_activeChannel"
                         Messages="_messages"
                         ThreadSummaries="_threadSummaries"
                         OnOpenThread="HandleOpenThread"
                         OnReact="HandleReact"
                         OnSendMessage="HandleSendMessage"
                         OnLoadOlderMessages="HandleLoadOlderMessages" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="HandleCloseThread"
                         OnSendReply="HandleSendReply" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = [];

    // Thread state
    private bool _threadOpen;
    private int? _threadRootMessageId;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        // Auto-select first channel if available
        if (_channels.Count > 0)
        {
            await HandleChannelSelected(_channels[0].Id);
        }
    }

    private async Task HandleChannelSelected(int channelId)
    {
        if (_activeChannelId == channelId) return;

        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);

        // Close any open thread when switching channels
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];

        // Load messages
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);

        // Build thread summaries from messages that have replies
        await BuildThreadSummariesAsync();

        // Mark channel as read
        await ChatService.MarkChannelReadAsync(channelId);

        // Update the channel's unread count locally
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            _channels[idx] = _channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task BuildThreadSummariesAsync()
    {
        _threadSummaries = [];

        // Identify messages that are thread roots (have replies pointing to them)
        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToList();

        // Also check messages that don't have ReplyToId but might be roots
        // by looking for messages referenced by others
        foreach (var rootId in rootIds)
        {
            var thread = await ChatService.GetThreadAsync(rootId);
            if (thread.Count > 0)
            {
                _threadSummaries[rootId] = new ThreadSummary(
                    rootId,
                    thread.Count,
                    thread.Max(t => t.SentAt));
            }
        }
    }

    private async Task HandleSendMessage(string content)
    {
        if (_activeChannelId is null) return;

        var message = await ChatService.SendMessageAsync(_activeChannelId.Value, content, null);
        _messages.Add(message);
    }

    private async Task HandleLoadOlderMessages()
    {
        if (_activeChannelId is null) return;

        var olderMessages = await ChatService.GetMessagesAsync(
            _activeChannelId.Value, _messages.Count, PageSize);

        if (olderMessages.Count > 0)
        {
            _messages.InsertRange(0, olderMessages);
        }
    }

    private async Task HandleOpenThread(int rootMessageId)
    {
        _threadRootMessageId = rootMessageId;
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);

        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        _threadOpen = true;
    }

    private Task HandleCloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
        return Task.CompletedTask;
    }

    private async Task HandleSendReply(string content)
    {
        if (_activeChannelId is null || _threadRootMessageId is null) return;

        var reply = await ChatService.SendMessageAsync(
            _activeChannelId.Value, content, _threadRootMessageId.Value);
        _threadReplies.Add(reply);

        // Update thread summary
        _threadSummaries[_threadRootMessageId.Value] = new ThreadSummary(
            _threadRootMessageId.Value,
            _threadReplies.Count,
            reply.SentAt);
    }

    private async Task HandleReact((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        UpdateReactionLocally(_messages, args.MessageId, args.Emoji);
        UpdateReactionLocally(_threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionLocally(List<Message> messages, int messageId, string emoji)
    {
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var reactions = msg.Reactions.ToList();
        var existingIdx = reactions.FindIndex(r => r.Emoji == emoji);
        if (existingIdx >= 0)
        {
            var r = reactions[existingIdx];
            if (!r.Users.Contains("You"))
            {
                reactions[existingIdx] = r with { Users = [.. r.Users, "You"] };
            }
        }
        else
        {
            reactions.Add(new Reaction(emoji, ["You"]));
        }

        messages[idx] = msg with { Reactions = reactions };
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    transition: flex 0.2s ease;
}

.chat-main.expanded {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #72767d;
    font-size: 1.1rem;
}

